"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
    Plus,
    Pencil,
    Trash2,
    Users,
    Percent,
    ShoppingBag,
    Coins,
    RefreshCw,
    Loader2,
    Check,
    X,
    GripVertical,
    AlertCircle,
    Edit,
    Save,
    Info,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/components/ui/toast";
import { ConfirmDialog } from "@/components/ui/confirm-dialog";
import { ResponsiveModal } from "@/components/ui/responsive-modal";
import { cn } from "@/lib/utils";
import { useBranding } from "@/components/branding-provider";
import { playSound } from "@/lib/sounds";
import { LoyaltyLevelBadge } from "@/app/(main)/dashboard/clients/components/loyalty-level-badge";
import {
    createLoyaltyLevel,
    updateLoyaltyLevel,
    deleteLoyaltyLevel,
    recalculateAllClientsLoyalty,
    toggleLoyaltyLevelActive,
    getLoyaltyLevels,
} from "@/app/(main)/dashboard/clients/actions/loyalty.actions";
import type { LoyaltyLevel } from "@/lib/schema/loyalty-levels";

interface LoyaltySettingsClientProps {
    initialLevels: LoyaltyLevel[];
    initialStats: {
        levelId: string;
        levelName: string;
        color: string;
        clientsCount: number;
        totalRevenue: number;
    }[];
}

// Предустановленные цвета
const COLOR_PRESETS = [
    "#64748b", // slate
    "#3b82f6", // blue
    "#10b981", // emerald
    "#f59e0b", // amber
    "#8b5cf6", // violet
    "#ec4899", // pink
    "#ef4444", // red
    "#06b6d4", // cyan
];

// Иконки
// const ICON_OPTIONS = [
//     { id: "user", label: "Пользователь" },
//     { id: "star", label: "Звезда" },
//     { id: "award", label: "Награда" },
//     { id: "crown", label: "Корона" },
//     { id: "sparkles", label: "Искры" },
// ];

export function LoyaltySettingsClient({ initialLevels, initialStats }: LoyaltySettingsClientProps) {
    const [levels, setLevels] = useState(initialLevels);
    const [stats] = useState(initialStats);
    const [editingLevel, setEditingLevel] = useState<LoyaltyLevel | null>(null);
    const [isCreateOpen, setIsCreateOpen] = useState(false);
    const [deletingLevel, setDeletingLevel] = useState<LoyaltyLevel | null>(null);
    const [recalculating, setRecalculating] = useState(false);
    const { toast } = useToast();
    const { currencySymbol } = useBranding();

    // Форма создания/редактирования
    const [formData, setFormData] = useState({
        levelKey: "",
        levelName: "",
        minOrdersAmount: 0,
        minOrdersCount: 0,
        discountPercent: 0,
        bonusDescription: "",
        color: "#64748b",
        icon: "star",
        priority: 0,
        isActive: true,
    });

    const resetForm = () => {
        setFormData({
            levelKey: "",
            levelName: "",
            minOrdersAmount: 0,
            minOrdersCount: 0,
            discountPercent: 0,
            bonusDescription: "",
            color: "#64748b",
            icon: "star",
            priority: levels.length,
            isActive: true,
        });
    };

    const openEditModal = (level: LoyaltyLevel) => {
        setFormData({
            levelKey: level.levelKey,
            levelName: level.levelName,
            minOrdersAmount: Number(level.minOrdersAmount || 0),
            minOrdersCount: Number(level.minOrdersCount || 0),
            discountPercent: Number(level.discountPercent || 0),
            bonusDescription: level.bonusDescription || "",
            color: level.color || "#64748b",
            icon: level.icon || "star",
            priority: level.priority || 0,
            isActive: level.isActive ?? true,
        });
        setEditingLevel(level);
    };

    const handleSave = async () => {
        if (!formData.levelName.trim()) {
            toast("Введите название уровня", "error");
            return;
        }

        if (editingLevel) {
            // Обновление
            const result = await updateLoyaltyLevel(editingLevel.id, formData);
            if (result.success) {
                toast("Уровень обновлён", "success");
                setLevels(prev => prev.map(l =>
                    l.id === editingLevel.id
                        ? { ...l, ...formData } as unknown as LoyaltyLevel
                        : l
                ));
                setEditingLevel(null);
            } else {
                toast((result as { error?: string }).error || "Ошибка", "error");
            }
        } else {
            // Создание
            if (!formData.levelKey.trim()) {
                toast("Введите ключ уровня", "error");
                return;
            }

            const result = await createLoyaltyLevel(formData);
            if (result.success && result.data) {
                toast("Уровень создан", "success");
                setLevels(prev => [...prev, result.data!]);
                setIsCreateOpen(false);
                resetForm();
            } else {
                toast((result as { error?: string }).error || "Ошибка", "error");
            }
        }
    };

    const handleDelete = async () => {
        if (!deletingLevel) return;

        const result = await deleteLoyaltyLevel(deletingLevel.id);
        if (result.success) {
            toast("Уровень удалён", "success");
            setLevels(prev => prev.filter(l => l.id !== deletingLevel.id));
        } else {
            toast((result as { error?: string }).error || "Ошибка", "error");
        }
        setDeletingLevel(null);
    };

    const handleSaveStatus = async (level: LoyaltyLevel) => {
        try {
            const result = await toggleLoyaltyLevelActive(level.id, !level.isActive);
            if (result.success) {
                setLevels(levels.map(l => l.id === level.id ? { ...l, isActive: !l.isActive } : l));
                toast(`Уровень "${level.levelName}" ${!level.isActive ? 'активирован' : 'деактивирован'}`, "success");
            } else {
                toast(result.error || "Не удалось изменить статус уровня", "error");
            }
        } catch {
            toast("Произошла ошибка при изменении статуса", "error");
        }
    };

    const handleRecalculate = async () => {
        setRecalculating(true);
        const result = await recalculateAllClientsLoyalty();
        setRecalculating(false);

        if (result.success && result.data) {
            toast(`Обработано и изменено клиентов: ${result.data.updatedCount}`, "success");
        } else {
            toast((result as { error?: string }).error || "Ошибка", "error");
        }
    };

    const getStatForLevel = (levelId: string) => {
        return stats.find(s => s.levelId === levelId);
    };

    return (
        <div className="space-y-6">
            {/* Header Actions */}
            <div className="flex flex-wrap items-center gap-3">
                <Button
                    onClick={() => {
                        resetForm();
                        setIsCreateOpen(true);
                    }}
                    className="h-11 px-6 rounded-xl text-sm font-bold"
                >
                    <Plus className="w-4 h-4 mr-2" />
                    Добавить уровень
                </Button>
                <Button
                    variant="outline"
                    onClick={handleRecalculate}
                    disabled={recalculating}
                    className="h-11 px-6 rounded-xl text-sm font-bold"
                >
                    {recalculating ? (
                        <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    ) : (
                        <RefreshCw className="w-4 h-4 mr-2" />
                    )}
                    Пересчитать всех клиентов
                </Button>
            </div>

            {/* Levels Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                <AnimatePresence mode="popLayout">
                    {levels
                        .sort((a, b) => (a.priority || 0) - (b.priority || 0))
                        .map((level, index) => {
                            const stat = getStatForLevel(level.id);

                            return (
                                <motion.div
                                    key={level.id}
                                    initial={{ opacity: 0, y: 20 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    exit={{ opacity: 0, scale: 0.95 }}
                                    transition={{ delay: index * 0.05 }}
                                    className={cn(
                                        "crm-card p-6 space-y-4",
                                        !level.isActive && "opacity-60"
                                    )}
                                >
                                    {/* Header */}
                                    <div className="flex items-start justify-between">
                                        <div className="flex items-center gap-3">
                                            <div
                                                className="w-12 h-12 rounded-xl flex items-center justify-center transition-colors"
                                                style={{ backgroundColor: `${level.color}20` }}
                                            >
                                                <LoyaltyLevelBadge
                                                    level={level}
                                                    size="lg"
                                                    showDiscount={false}
                                                    className="!bg-transparent !px-0"
                                                />
                                            </div>
                                            <div>
                                                <h3 className="text-lg font-bold text-slate-900">
                                                    {level.levelName}
                                                </h3>
                                                <p className="text-[11px] text-slate-400 font-mono">
                                                    {level.levelKey}
                                                </p>
                                            </div>
                                        </div>
                                        <div className="flex gap-1">
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                onClick={() => openEditModal(level)}
                                                className="h-8 w-8 p-0 rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                                            >
                                                <Pencil className="w-4 h-4" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                onClick={() => setDeletingLevel(level)}
                                                className="h-8 w-8 p-0 rounded-lg text-rose-500 hover:bg-rose-50 outline-none focus:ring-2 focus:ring-rose-200"
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </Button>
                                        </div>
                                    </div>

                                    {/* Thresholds */}
                                    <div className="grid grid-cols-2 gap-3">
                                        <div className="p-3 bg-slate-50 rounded-xl">
                                            <div className="flex items-center gap-2 text-slate-500 mb-1">
                                                <Coins className="w-3.5 h-3.5" />
                                                <span className="text-[10px] font-bold">Мин. сумма</span>
                                            </div>
                                            <p className="text-sm font-bold text-slate-900">
                                                {Number(level.minOrdersAmount || 0).toLocaleString()} {currencySymbol}
                                            </p>
                                        </div>
                                        <div className="p-3 bg-slate-50 rounded-xl">
                                            <div className="flex items-center gap-2 text-slate-500 mb-1">
                                                <ShoppingBag className="w-3.5 h-3.5" />
                                                <span className="text-[10px] font-bold">Мин. заказов</span>
                                            </div>
                                            <p className="text-sm font-bold text-slate-900">
                                                {level.minOrdersCount || 0}
                                            </p>
                                        </div>
                                    </div>

                                    {/* Discount */}
                                    {Number(level.discountPercent || 0) > 0 && (
                                        <div className="flex items-center gap-2 p-3 bg-emerald-50 rounded-xl">
                                            <Percent className="w-4 h-4 text-emerald-600" />
                                            <span className="text-sm font-bold text-emerald-700">
                                                Скидка {level.discountPercent}%
                                            </span>
                                        </div>
                                    )}

                                    {/* Stats */}
                                    {stat && (
                                        <div className="pt-4 border-t border-slate-100">
                                            <div className="flex items-center justify-between text-xs">
                                                <div className="flex items-center gap-1.5 text-slate-500">
                                                    <Users className="w-3.5 h-3.5" />
                                                    <span className="font-bold">{stat.clientsCount} клиентов</span>
                                                </div>
                                                <span className="font-bold text-slate-900">
                                                    {stat.totalRevenue.toLocaleString()} {currencySymbol}
                                                </span>
                                            </div>
                                        </div>
                                    )}

                                    {/* Inactive Badge */}
                                    {!level.isActive && (
                                        <div className="flex items-center gap-2 text-amber-600 text-xs font-bold">
                                            <X className="w-3.5 h-3.5" />
                                            Неактивен
                                        </div>
                                    )}
                                </motion.div>
                            );
                        })}
                </AnimatePresence>
            </div>

            {/* Create/Edit Modal */}
            <ResponsiveModal
                isOpen={isCreateOpen || !!editingLevel}
                onClose={() => {
                    setIsCreateOpen(false);
                    setEditingLevel(null);
                }}
                title={editingLevel ? "Редактировать уровень" : "Новый уровень"}
                className="max-w-lg"
            >
                <div className="p-6 space-y-4">
                    {/* Key & Name */}
                    <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-slate-700 ml-1">
                                Ключ <span className="text-rose-500">*</span>
                            </label>
                            <Input
                                type="text"
                                value={formData.levelKey}
                                onChange={(e) => setFormData(prev => ({
                                    ...prev,
                                    levelKey: e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, "")
                                }))}
                                placeholder="gold"
                                disabled={!!editingLevel}
                                className="h-12 rounded-xl"
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-slate-700 ml-1">
                                Название <span className="text-rose-500">*</span>
                            </label>
                            <Input
                                type="text"
                                value={formData.levelName}
                                onChange={(e) => setFormData(prev => ({ ...prev, levelName: e.target.value }))}
                                placeholder="Золото"
                                className="h-12 rounded-xl"
                            />
                        </div>
                    </div>

                    {/* Thresholds */}
                    <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-slate-700 ml-1">
                                Мин. сумма заказов
                            </label>
                            <Input
                                type="number"
                                value={formData.minOrdersAmount}
                                onChange={(e) => setFormData(prev => ({ ...prev, minOrdersAmount: Number(e.target.value) }))}
                                min={0}
                                className="h-12 rounded-xl"
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-slate-700 ml-1">
                                Мин. количество заказов
                            </label>
                            <Input
                                type="number"
                                value={formData.minOrdersCount}
                                onChange={(e) => setFormData(prev => ({ ...prev, minOrdersCount: Number(e.target.value) }))}
                                min={0}
                                className="h-12 rounded-xl"
                            />
                        </div>
                    </div>

                    {/* Discount */}
                    <div className="space-y-2">
                        <label className="text-sm font-bold text-slate-700 ml-1">
                            Скидка (%)
                        </label>
                        <Input
                            type="number"
                            value={formData.discountPercent}
                            onChange={(e) => setFormData(prev => ({ ...prev, discountPercent: Number(e.target.value) }))}
                            min={0}
                            max={100}
                            className="h-12 rounded-xl"
                        />
                    </div>

                    {/* Color */}
                    <div className="space-y-2">
                        <label className="text-sm font-bold text-slate-700 ml-1">
                            Цвет
                        </label>
                        <div className="flex flex-wrap gap-2">
                            {COLOR_PRESETS.map((color) => (
                                <button
                                    key={color}
                                    type="button"
                                    onClick={() => setFormData(prev => ({ ...prev, color }))}
                                    className={cn(
                                        "w-10 h-10 rounded-xl border-2 transition-all",
                                        formData.color === color
                                            ? "border-slate-900 scale-110"
                                            : "border-transparent hover:scale-105"
                                    )}
                                    style={{ backgroundColor: color }}
                                />
                            ))}
                            <input
                                type="color"
                                value={formData.color}
                                onChange={(e) => setFormData(prev => ({ ...prev, color: e.target.value }))}
                                className="w-10 h-10 rounded-xl cursor-pointer"
                            />
                        </div>
                    </div>

                    {/* Priority */}
                    <div className="space-y-2">
                        <label className="text-sm font-bold text-slate-700 ml-1">
                            Приоритет (чем выше — тем престижнее)
                        </label>
                        <Input
                            type="number"
                            value={formData.priority}
                            onChange={(e) => setFormData(prev => ({ ...prev, priority: Number(e.target.value) }))}
                            className="h-12 rounded-xl"
                        />
                    </div>

                    {/* Active */}
                    <label className="flex items-center gap-3 p-4 bg-slate-50 rounded-xl cursor-pointer hover:bg-slate-100 transition-colors">
                        <input
                            type="checkbox"
                            checked={formData.isActive}
                            onChange={(e) => setFormData(prev => ({ ...prev, isActive: e.target.checked }))}
                            className="w-5 h-5 rounded border-slate-300 text-primary focus:ring-primary"
                        />
                        <div>
                            <p className="text-sm font-bold text-slate-900">Активен</p>
                            <p className="text-[11px] text-slate-500">Уровень доступен для назначения</p>
                        </div>
                    </label>

                    {/* Actions */}
                    <div className="flex gap-3 pt-4 border-t border-slate-100">
                        <Button
                            type="button"
                            variant="ghost"
                            onClick={() => {
                                setIsCreateOpen(false);
                                setEditingLevel(null);
                            }}
                            className="flex-1 h-11 rounded-xl text-sm font-bold"
                        >
                            Отмена
                        </Button>
                        <Button
                            type="button"
                            onClick={handleSave}
                            className="flex-1 h-11 rounded-xl text-sm font-bold"
                        >
                            {editingLevel ? "Сохранить" : "Создать"}
                        </Button>
                    </div>
                </div>
            </ResponsiveModal>

            {/* Delete Confirmation */}
            <ConfirmDialog
                isOpen={!!deletingLevel}
                onClose={() => setDeletingLevel(null)}
                onConfirm={handleDelete}
                title="Удаление уровня"
                description={`Вы уверены, что хотите удалить уровень "${deletingLevel?.levelName}"?`}
                variant="destructive"
                confirmText="Удалить"
            />
        </div>
    );
}

"use server";

import { db } from "@/lib/db";
import { clients, orders, loyaltyLevels } from "@/lib/schema";
import { users } from "@/lib/schema";
import { eq, sql, and, gte, lte, desc, count, sum, avg, isNotNull, isNull, ne } from "drizzle-orm";
import { logError } from "@/lib/error-logger";
import { funnelStages, funnelStageLabels, funnelStageColors } from "@/lib/schema/clients";
import { rfmSegmentLabels, rfmSegmentColors } from "./rfm.types";

// === ТИПЫ ===
