    totalClients: number;
    activeClients: number;
    atRiskClients: number;
    lostClients: number;
    newClientsThisMonth: number;
    newClientsLastMonth: number;
    newClientsGrowth: number;
    totalRevenue: number;
    averageCheck: number;
    averageLTV: number;
    b2cCount: number;
    b2bCount: number;
}

