        revalidatePath("/dashboard/clients/analytics/loyalty");
        return { success: true, data: updated };
    } catch (error) {
        await logError({ error, details: { context: "toggleLoyaltyLevelActive", id, isActive } });
        return { success: false, error: "Ошибка изменения статуса уровня" };
    }
}

/**
 * Удалить уровень лояльности
 */
export async function deleteLoyaltyLevel(id: string): Promise<ActionResult> {
    const session = await getSession();
    if (session?.role !== "admin") return { success: false, error: "Access denied" };

    try {
        await db.delete(loyaltyLevels).where(eq(loyaltyLevels.id, id));
        await logAction("delete_loyalty_level", "loyalty_level", id);
        revalidatePath("/dashboard/clients/analytics/loyalty");
        return { success: true };
    } catch (error) {
        await logError({ error, details: { context: "deleteLoyaltyLevel", id } });
        return { success: false, error: "Ошибка удаления уровня" };
    }
}

/**
 * Изменить порядок уровней
 */
export async function reorderLoyaltyLevels(items: { id: string; priority: number }[]): Promise<ActionResult> {
    const session = await getSession();
    if (session?.role !== "admin") return { success: false, error: "Access denied" };

    try {
        await db.transaction(async (tx) => {
            for (const item of items) {
                await tx
                    .update(loyaltyLevels)
                    .set({ priority: item.priority })
                    .where(eq(loyaltyLevels.id, item.id));
            }
        });

        await logAction("reorder_loyalty_levels", "loyalty_level", "system", { items });
        revalidatePath("/dashboard/clients/analytics/loyalty");
        return { success: true };
    } catch (error) {
        await logError({ error, details: { context: "reorderLoyaltyLevels" } });
        return { success: false, error: "Ошибка изменения порядка" };
    }
}

/**
 * Установить уровень лояльности клиента (вручную или авто)
 */
export async function setClientLoyaltyLevel(clientId: string, levelId: string | null, setManually: boolean = false): Promise<ActionResult> {
    const session = await getSession();
    if (!session) return { success: false, error: "Unauthorized" };

    try {
        await db
            .update(clients)
            .set({
                loyaltyLevelId: levelId,
                loyaltyLevelSetManually: setManually,
                loyaltyLevelChangedAt: new Date(),
                updatedAt: new Date()
            })
            .where(eq(clients.id, clientId));

        await logAction(
            "set_loyalty_level",
            "client",
            clientId,
            { levelId, setManually }
        );

        revalidatePath("/dashboard/clients");
        revalidatePath(`/dashboard/clients/${clientId}`);

        return { success: true };
    } catch (error) {
        await logError({
            error,
            details: { context: "setClientLoyaltyLevel", clientId, levelId }
        });
        return { success: false, error: "Ошибка установки уровня" };
    }
}

/**
 * Пересчитать лояльность для всех клиентов
 */
export async function recalculateAllClientsLoyalty(): Promise<ActionResult<{ updatedCount: number }>> {
    const session = await getSession();
    if (session?.role !== "admin") return { success: false, error: "Access denied" };

    try {
        const levels = await db.query.loyaltyLevels.findMany({
            where: eq(loyaltyLevels.isActive, true),
            orderBy: [desc(loyaltyLevels.priority)],
        });

        let updatedCount = 0;

        const allClients = await db.query.clients.findMany({
            where: eq(clients.loyaltyLevelSetManually, false)
        });

        for (const client of allClients) {
            const amount = Number(client.totalOrdersAmount) || 0;
            const count = client.totalOrdersCount || 0;

            const targetLevel = levels.find(l =>
                amount >= (Number(l.minOrdersAmount) || 0) &&
                count >= (l.minOrdersCount || 0)
            );

            const targetLevelId = targetLevel?.id || null;

            if (client.loyaltyLevelId !== targetLevelId) {
                await db
                    .update(clients)
                    .set({
                        loyaltyLevelId: targetLevelId,
                        loyaltyLevelChangedAt: new Date(),
                        updatedAt: new Date()
                    })
                    .where(eq(clients.id, client.id));
                updatedCount++;
            }
        }

        await logAction("recalculate_loyalty_all", "client", "system", { updatedCount });
        revalidatePath("/dashboard/clients");

        return { success: true, data: { updatedCount } };
    } catch (error) {
        await logError({ error, details: { context: "recalculateAllClientsLoyalty" } });
        return { success: false, error: "Ошибка пересчета лояльности" };
    }
}

"use server";

import { db } from "@/lib/db";
import { clients } from "@/lib/schema";
import { eq, and, desc, sql, count, isNotNull } from "drizzle-orm";
import { getSession } from "@/lib/auth";
import { logError } from "@/lib/error-logger";
import { logAction } from "@/lib/audit";
import { revalidatePath } from "next/cache";

import { rfmSegments, RFMSegment, rfmSegmentLabels, rfmSegmentColors, rfmSegmentDescriptions } from "./rfm.types";

// === ФУНКЦИИ ===

/**
 * Рассчитать RFM-скор для значения
 * @param value - значение метрики
 * @param thresholds - пороговые значения [низкий, средний, высокий, очень высокий]
 * @returns скор от 1 до 5
 */
function calculateScore(value: number, thresholds: number[]): number {
    if (value <= thresholds[0]) return 1;
    if (value <= thresholds[1]) return 2;
    if (value <= thresholds[2]) return 3;
    if (value <= thresholds[3]) return 4;
    return 5;
}

/**
 * Определить RFM-сегмент по скорам
 */
function determineSegment(r: number, f: number, m: number): RFMSegment {
    // Чемпионы: R=5, F>=4, M>=4
    if (r === 5 && f >= 4 && m >= 4) return "champions";

    // Лояльные: R>=4, F>=3, M>=3
    if (r >= 4 && f >= 3 && m >= 3) return "loyal";

    // Потенциальные: R>=4, F>=2, M>=2
    if (r >= 4 && f >= 2 && m >= 2) return "potential";

    // Новые: R=5, F=1
    if (r === 5 && f === 1) return "new";

    // Перспективные: R>=4, F=1
    if (r >= 4 && f === 1) return "promising";

    // Требуют внимания: R=3, F>=3, M>=3
    if (r === 3 && f >= 3 && m >= 3) return "need_attention";

    // Засыпающие: R=3, F<3
    if (r === 3 && f < 3) return "about_to_sleep";

    // В зоне риска: R<=2, F>=3, M>=3
    if (r <= 2 && f >= 3 && m >= 3) return "at_risk";

    // Спящие: R<=2, F>=2
    if (r <= 2 && f >= 2) return "hibernating";

    // Потерянные: R=1
    return "lost";
}

/**
 * Рассчитать RFM для одного клиента
 */
export async function calculateClientRFM(clientId: string): Promise<{
    success: boolean;
    data?: {
        recency: number;
        frequency: number;
        monetary: number;
        score: string;
        segment: RFMSegment;
    };
    error?: string;
}> {
    try {
        const session = await getSession();
        if (!session) return { success: false, error: "Не авторизован" };

        // Получаем данные клиента
        const client = await db.query.clients.findFirst({
            where: eq(clients.id, clientId),
        });

        if (!client) {
            return { success: false, error: "Клиент не найден" };
        }

        // Пороги для Recency (меньше = лучше, инвертируем)
        const recencyThresholds = [30, 60, 90, 180]; // дни
        const recencyValue = Number(client.daysSinceLastOrder) || 365;
        const recencyScore = Math.max(1, 6 - calculateScore(recencyValue, recencyThresholds));

        // Пороги для Frequency
        const frequencyThresholds = [1, 3, 5, 10];
        const frequencyValue = Number(client.totalOrdersCount) || 0;
        const frequencyScore = calculateScore(frequencyValue, frequencyThresholds);

        // Пороги для Monetary
        const monetaryThresholds = [5000, 15000, 50000, 150000];
        const monetaryValue = Number(client.totalOrdersAmount) || 0;
        const monetaryScore = calculateScore(monetaryValue, monetaryThresholds);

        // Определяем сегмент
        const segment = determineSegment(recencyScore, frequencyScore, monetaryScore);
        const score = `${recencyScore}${frequencyScore}${monetaryScore}`;

        // Сохраняем в БД
        await db
            .update(clients)
            .set({
                rfmRecency: recencyScore,
                rfmFrequency: frequencyScore,
                rfmMonetary: monetaryScore,
                rfmScore: score,
                rfmSegment: segment,
                rfmCalculatedAt: new Date(),
            })
            .where(eq(clients.id, clientId));

        revalidatePath("/dashboard/clients");

        return {
            success: true,
            data: {
                recency: recencyScore,
                frequency: frequencyScore,
                monetary: monetaryScore,
                score,
                segment,
            },
        };
    } catch (error) {
        logError({ error, details: { action: "calculateClientRFM", clientId } });
        return { success: false, error: "Не удалось рассчитать RFM" };
    }
}

/**
 * Рассчитать RFM для всех клиентов
 */
export async function calculateAllClientsRFM(): Promise<{
    success: boolean;
    data?: { updated: number };
    error?: string;
}> {
    try {
        const session = await getSession();
        if (!session) return { success: false, error: "Не авторизован" };

        // Получаем всех активных клиентов
        const allClients = await db
            .select({
                id: clients.id,
                daysSinceLastOrder: clients.daysSinceLastOrder,
                totalOrdersCount: clients.totalOrdersCount,
                totalOrdersAmount: clients.totalOrdersAmount,
            })
            .from(clients)
            .where(eq(clients.isArchived, false));

        let updated = 0;

        for (const client of allClients) {
            // Пороги
            const recencyThresholds = [30, 60, 90, 180];
            const frequencyThresholds = [1, 3, 5, 10];
            const monetaryThresholds = [5000, 15000, 50000, 150000];

            const recencyValue = Number(client.daysSinceLastOrder) || 365;
            const recencyScore = Math.max(1, 6 - calculateScore(recencyValue, recencyThresholds));

            const frequencyScore = calculateScore(Number(client.totalOrdersCount) || 0, frequencyThresholds);
            const monetaryScore = calculateScore(Number(client.totalOrdersAmount) || 0, monetaryThresholds);

            const segment = determineSegment(recencyScore, frequencyScore, monetaryScore);
            const score = `${recencyScore}${frequencyScore}${monetaryScore}`;

            await db
                .update(clients)
                .set({
                    rfmRecency: recencyScore,
                    rfmFrequency: frequencyScore,
                    rfmMonetary: monetaryScore,
                    rfmScore: score,
                    rfmSegment: segment,
                    rfmCalculatedAt: new Date(),
                })
                .where(eq(clients.id, client.id));

            updated++;
        }

        await logAction(
            "calculate_all_rfm",
            "client",
            "bulk",
            { updated }
        );

        revalidatePath("/dashboard/clients");

        return { success: true, data: { updated } };
    } catch (error) {
        logError({ error, details: { action: "calculateAllClientsRFM" } });
        return { success: false, error: "Не удалось рассчитать RFM" };
    }
}

/**
 * Получить статистику по RFM-сегментам
 */
export async function getRFMStats(): Promise<{
    success: boolean;
    data?: Array<{
        segment: string;
        label: string;
        color: string;
        count: number;
        percentage: number;
        averageCheck: number;
        totalAmount: number;
    }>;
    error?: string;
}> {
    try {
        const segmentData = await db
            .select({
                segment: clients.rfmSegment,
                count: count(),
                avgRevenue: sql<number>`AVG(COALESCE(${clients.totalOrdersAmount}, 0))`,
            })
            .from(clients)
            .where(and(eq(clients.isArchived, false), isNotNull(clients.rfmSegment)))
            .groupBy(clients.rfmSegment);

        const total = segmentData.reduce((sum, s) => sum + Number(s.count), 0);

        const result = segmentData.map((row) => ({
            segment: row.segment || "unknown",
