                    <Button
                        onClick={() => handleOpenModal()}
                        size="sm"
                        className="h-9 rounded-xl gap-2 font-black bg-slate-900 shadow-lg shadow-slate-200 active:scale-95"
                    >
                        <Plus className="w-4 h-4" />
                        Добавить уровень
                    </Button>
                </div>

                <Reorder.Group axis="y" values={levels} onReorder={handleReorder} className="space-y-3">
                    {levels.map((level) => (
                        <Reorder.Item
                            key={level.id}
                            value={level}
                            className="group relative"
                        >
                            <div className={cn(
                                "bg-white p-5 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-6 transition-all hover:shadow-md hover:border-slate-200 cursor-default",
                                !level.isActive && "opacity-60 saturate-50"
                            )}>
                                <div className="cursor-grab active:cursor-grabbing text-slate-300 hover:text-slate-500 transition-colors">
                                    <GripVertical className="w-5 h-5" />
                                </div>

                                <div
                                    className="w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner shrink-0"
                                    style={{ backgroundColor: `${level.color || '#F1F5F9'}15`, color: level.color || '#64748B' }}
                                >
                                    <Trophy className="w-7 h-7" />
                                </div>

                                <div className="flex-1">
                                    <div className="flex items-center gap-3">
                                        <h5 className="font-black text-slate-900 text-lg tracking-tight">{level.levelName}</h5>
                                        {!level.isActive && (
                                            <span className="text-[10px] font-black uppercase tracking-wider bg-slate-100 text-slate-400 px-2 py-0.5 rounded-full">
                                                Черновик
                                            </span>
                                        )}
                                    </div>
                                    <div className="flex items-center gap-4 mt-1">
                                        <div className="flex items-center gap-1.5 text-xs font-bold text-slate-500">
                                            <Target className="w-3.5 h-3.5" />
                                            <span>от {Number(level.minOrdersAmount).toLocaleString()} ₽</span>
                                        </div>
                                        <div className="flex items-center gap-1.5 text-xs font-bold text-slate-500">
                                            <RefreshCw className="w-3.5 h-3.5" />
                                            <span>от {level.minOrdersCount || 0} зак.</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center gap-3 px-6 border-x border-slate-100">
                                    <div className="text-center">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Скидка</p>
                                        <div className="flex items-center justify-center gap-1">
                                            <span className="text-xl font-black text-slate-900">{level.discountPercent || 0}</span>
                                            <Percent className="w-3.5 h-3.5 text-slate-400" />
                                        </div>
                                    </div>
                                    <div className="w-px h-8 bg-slate-50 mx-2" />
                                    <div className="text-center">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Бонусы</p>
                                        <div className="flex items-center justify-center gap-1">
                                            <span className="text-xl font-black text-slate-900">{level.cashbackPercent || 0}</span>
                                            <Coins className="w-3.5 h-3.5 text-slate-400" />
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center gap-2">
                                    <Button variant="ghost" size="icon" className="h-10 w-10 rounded-xl" onClick={() => handleOpenModal(level)}>
                                        <Edit2 className="w-4 h-4 text-slate-400" />
                                    </Button>
                                    <Button variant="ghost" size="icon" className="h-10 w-10 rounded-xl hover:bg-red-50 hover:text-red-500" onClick={() => handleDelete(level.id)}>
                                        <Trash2 className="w-4 h-4 text-slate-400 group-hover:text-red-500" />
                                    </Button>
                                </div>
                            </div>
                        </Reorder.Item>
                    ))}
                </Reorder.Group>
            </div>

            {/* Modal */}
            <ResponsiveModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={editingLevel ? "Редактировать уровень" : "Новый уровень"}
                description="Настройте условия и привилегии для клиентов"
            >
                <div className="p-6 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-4">
                            <div>
                                <label className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2 block">Название этапа</label>
                                <Input
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
