                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2 block">Сумма покупок</label>
                                    <div className="relative">
                                        <Input
                                            type="number"
                                            value={formData.minOrdersAmount}
                                            onChange={e => setFormData({ ...formData, minOrdersAmount: e.target.value })}
                                            className="h-12 rounded-xl pl-4 pr-10 font-bold border-slate-200"
                                        />
                                        <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 font-bold">₽</span>
                                    </div>
                                </div>
                                <div>
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2 block">Кол-во заказов</label>
                                    <Input
                                        type="number"
                                        value={formData.minOrdersCount}
                                        onChange={e => setFormData({ ...formData, minOrdersCount: e.target.value })}
