                                        onChange={e => setFormData({ ...formData, discountPercent: e.target.value })}
                                        className="h-12 rounded-xl font-black text-indigo-600 border-slate-200"
                                    />
                                </div>
                                <div>
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2 block">Бонусы %</label>
                                    <Input
                                        type="number"
                                        value={formData.cashbackPercent}
                                        onChange={e => setFormData({ ...formData, cashbackPercent: e.target.value })}
                                        className="h-12 rounded-xl font-black text-emerald-600 border-slate-200"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2 block">Цвет иконки</label>
                                <div className="flex gap-2 flex-wrap">
                                    {availableColors.map(color => (
                                        <button
                                            key={color}
                                            onClick={() => setFormData({ ...formData, color })}
                                            className={cn(
                                                "w-8 h-8 rounded-full border-4 border-white shadow-sm transition-transform active:scale-90",
                                                formData.color === color ? "scale-110 ring-2 ring-slate-200" : "scale-100"
                                            )}
                                            style={{ backgroundColor: color }}
                                        />
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="pt-6 border-t border-slate-100 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Switch
                                checked={formData.isActive}
                                onCheckedChange={checked => setFormData({ ...formData, isActive: checked })}
                            />
