                        </div>

                        <div className="flex gap-3">
                            <Button variant="ghost" onClick={() => setIsModalOpen(false)} className="h-12 px-6 rounded-xl font-bold">
                                Отмена
                            </Button>
                            <Button onClick={handleSave} className="h-12 px-8 rounded-xl font-black bg-indigo-600 shadow-lg shadow-indigo-100 active:scale-95">
                                Сохранить уровень
                            </Button>
                        </div>
                    </div>
                </div>
            </ResponsiveModal>
        </div>
    );
}

