export const DuplicateWarningModal = memo(function DuplicateWarningModal({
    isOpen,
    onClose,
    onIgnore,
    onOpenClient,
    duplicates,
    isLoading = false,
}: DuplicateWarningModalProps) {
    if (duplicates.length === 0) return null;

    return (
        <ResponsiveModal
            isOpen={isOpen}
            onClose={onClose}
            title=""
            className="max-w-lg"
        >
            <div className="p-6 space-y-6">
