                        { label: "Цвет", value: selectedColorName, icon: () => <div className="w-2.5 h-2.5 rounded-full border border-black/10" style={{ backgroundColor: selectedColorHex }} /> },
                        { label: "Размер", value: getAttrName("size", formData.sizeCode), icon: Ruler },
                        { label: "Качество", value: getAttrName("quality", formData.qualityCode), icon: CheckCircle2 },
                        { label: "Материал", value: getAttrName("material", formData.materialCode), icon: Shirt },
                        // Packaging specific
                        {
                            label: "Габариты",
                            value: (formData.width && formData.height && formData.depth)
                                ? `${formData.depth}x${formData.width}x${formData.height}`
                                : null,
                            icon: Box
                        },
                        {
                            label: "Вес (1 шт)",
                            value: formData.weight ? `${formData.weight} гр` : null,
                            icon: Scale
                        },
                        {
                            label: "Тип упаковки",
                            value: formData.packagingType ? (formData.packagingType === "transport" ? "Транспортная" : "Индивидуальная") : null,
                            icon: Package
                        }
                    ].filter(i => i.value).map((item, idx) => {
                        const Icon = item.icon;
                        return (
                            <div key={idx} className="flex flex-col p-4 rounded-2xl bg-slate-50/50 border border-slate-100 hover:bg-white hover:border-slate-200 transition-all group">
                                <div className="flex items-center gap-2 mb-2">
                                    <div className="w-6 h-6 rounded-lg bg-white border border-slate-200 flex items-center justify-center text-slate-400 group-hover:text-slate-900 transition-colors">
                                        <Icon className="w-3.5 h-3.5" />
                                    </div>
                                    <span className="text-xs font-black text-slate-700">{item.label}</span>
                                </div>
                                <span className="text-sm font-bold text-slate-900">{item.value}</span>
                            </div>
                        )
                    })}
                </div>

                {/* Packaging - Logistics & Features */}
                {(formData.supplierName || (formData.features && formData.features.length > 0)) && (
                    <div className="mt-8 pt-8 border-t border-slate-100 grid grid-cols-1 md:grid-cols-2 gap-3">
                        {formData.supplierName && (
                            <div className="space-y-3">
                                <h4 className="text-xs font-black text-slate-400 leading-none">Логистика</h4>
                                <div className="p-4 rounded-2xl bg-indigo-50/50 border border-indigo-100/50 space-y-2">
                                    <div className="flex items-center justify-between">
                                        <span className="text-xs font-bold text-slate-500">Поставщик:</span>
                                        <span className="text-sm font-bold text-slate-900">{formData.supplierName}</span>
                                    </div>
                                    {formData.minBatch && (
                                        <div className="flex items-center justify-between">
                                            <span className="text-xs font-bold text-slate-500">Мин. партия:</span>
                                            <span className="text-sm font-bold text-slate-900">{formData.minBatch} шт</span>
                                        </div>
                                    )}
                                    {formData.supplierLink && (
                                        <div className="pt-2">
                                            <a
                                                href={formData.supplierLink}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="inline-flex items-center gap-2 text-xs font-bold text-indigo-600 hover:text-indigo-700 hover:underline"
                                            >
                                                <ExternalLink className="w-3 h-3" />
                                                Страница товара
                                            </a>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}

                        {formData.features && formData.features.length > 0 && (
                            <div className="space-y-3">
                                <h4 className="text-xs font-black text-slate-400 leading-none">Особенности</h4>
                                <div className="flex flex-wrap gap-2 text-[11px] font-bold">
                                    {formData.features.includes("glued_valve") && (
                                        <span className="px-3 py-1.5 rounded-full bg-emerald-50 text-emerald-600 border border-emerald-100">Клеевой клапан</span>
                                    )}
                                    {formData.features.includes("tear_tape") && (
                                        <span className="px-3 py-1.5 rounded-full bg-blue-50 text-blue-600 border border-blue-100">Отрывная лента</span>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {/* Custom Extra Attributes if any */}
                {(() => {
                    const predefinedKeys = ["brand", "color", "size", "quality", "material", "width", "height", "depth", "weight", "packagingType", "supplierName", "supplierLink", "minBatch", "features"];

                    const filteredItems = Object.entries(formData.attributes || {})
                        .map(([key, value]) => {
                            if (!value || typeof value !== 'string') return null;
                            if (predefinedKeys.includes(key.toLowerCase())) return null;
                            if (/^[a-f0-9-]{36}$/.test(key) || /^[a-f0-9-]{36}$/.test(value)) return null;

                            const type = attributeTypes?.find(t => t.slug === key);
                            if (!type) return null;

                            const attr = dynamicAttributes?.find(a => a.type === key && a.value === value);
                            let displayValue = attr?.name || value;

                            // Страна всегда с большой буквы
                            const isCountry = type.slug === 'country' || type.name.toLowerCase().includes('страна');
                            if (isCountry && displayValue) {
                                displayValue = displayValue.charAt(0).toUpperCase() + displayValue.slice(1);
                            }

                            return {
                                label: type.name,
                                displayValue,
                                slug: key,
                                showInName: type.showInName !== false
                            };
                        })
                        .filter((chip): chip is NonNullable<typeof chip> => {
                            if (!chip) return false;
                            if (!chip.showInName) return false;
                            const lowerSlug = chip.slug.toLowerCase();
                            if (lowerSlug.endsWith('code')) return false;
                            if (["thumbnailsettings"].includes(lowerSlug)) return false;
                            return true;
                        });

                    if (filteredItems.length === 0) return null;

                    return (
                        <div className="mt-8 pt-8 border-t border-slate-100">
                            <div className="flex flex-wrap gap-3">
                                {filteredItems.map((chip) => (
                                    <div key={chip.slug} className="px-4 py-2 bg-slate-50 rounded-xl border border-slate-200/50 flex items-center gap-3 shadow-sm group hover:border-slate-300 transition-all">
                                        <div className="w-1.5 h-1.5 rounded-full bg-slate-300 group-hover:bg-slate-900 transition-colors" />
                                        <span className="text-[11px] font-bold text-slate-700">{chip.label}:</span>
                                        <span className="text-sm font-bold text-slate-900">{chip.displayValue}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    );
                })()}
            </div>
        </div>
    );
}

import { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import { useNewItemForm, DEFAULT_FORM_DATA } from "./useNewItemForm";
import { ItemFormData, Category, StorageLocation, AttributeType } from "@/app/(main)/dashboard/warehouse/types";
import { addInventoryItem } from "@/app/(main)/dashboard/warehouse/item-actions";
import { useToast } from "@/components/ui/toast";
import { playSound } from "@/lib/sounds";
import { ROUTES } from "@/lib/routes";
import { sortCategories } from "@/app/(main)/dashboard/warehouse/category-utils";

const CATEGORY_TYPES = {
    packaging: "упаковка",
    clothing: "одежда",
    consumables: "расходники",
    uncategorized: "без категории",
} as const;

interface UseNewItemLogicProps {
    categories: Category[];
    storageLocations: StorageLocation[];
    initialCategoryId?: string;
    initialSubcategoryId?: string;
    attributeTypes: AttributeType[];
}

export function useNewItemLogic({
    categories,
    initialCategoryId,
    initialSubcategoryId,
    attributeTypes: _attributeTypes
}: UseNewItemLogicProps) {
    const router = useRouter();
    const { toast } = useToast();

    const [isMounted, setIsMounted] = useState(false);

    const {
        step, setStep,
        selectedCategory, setSelectedCategory,
        formData, setFormData,
        validationError, setValidationError,
        isSaving, setIsSaving,
        isSubmitting, setIsSubmitting,
        resetForm
    } = useNewItemForm();

    const updateFormData = useCallback((updates: Partial<ItemFormData> | ((prev: ItemFormData) => Partial<ItemFormData>)) => {
        setFormData((prev: ItemFormData) => {
            const resolvedUpdates = typeof updates === "function" ? updates(prev) : updates;
            return { ...prev, ...resolvedUpdates };
        });
        if (validationError) setValidationError("");
    }, [validationError, setFormData, setValidationError]);

    // Load initial state and draft after mount
    useEffect(() => {
        Promise.resolve().then(() => {
            setIsMounted(true);
        });

        // 1. Initial params
        let initialStep = 0;
        let initialCat: Category | null = null;
        let initialForm = { ...DEFAULT_FORM_DATA };

        if (initialSubcategoryId || initialCategoryId) {
            let resolvedSubId = initialSubcategoryId;
            let resolvedCatId = initialCategoryId;

            if (!resolvedSubId && resolvedCatId) {
                const cat = categories.find(c => c.id === resolvedCatId);
                if (cat?.parentId) {
                    resolvedSubId = resolvedCatId;
                    resolvedCatId = cat.parentId;
                }
            }

            initialCat = resolvedCatId ? (categories.find(c => c.id === resolvedCatId) || null) : null;

            if (initialCat) {
                const hasSubs = categories.some(c => c.parentId === initialCat?.id);
                if (!hasSubs || resolvedSubId) {
                    initialStep = 2;
                }
            }

            if (resolvedSubId) {
                const subCat = categories.find(c => c.id === resolvedSubId);
                const cleanSubName = subCat?.name.toLowerCase().trim() || "";
                const cleanInitialName = initialCat?.name.toLowerCase().trim() || "";
                const isClothing = cleanSubName.includes(CATEGORY_TYPES.clothing) || cleanInitialName.includes(CATEGORY_TYPES.clothing);
                initialForm = {
                    ...initialForm,
                    subcategoryId: resolvedSubId
                };
            }
        } else {
            // 2. Draft
            const saved = typeof window !== "undefined" ? localStorage.getItem("merch_crm_new_item_draft") : null;
            if (saved) {
                try {
                    const draft = JSON.parse(saved);
                    initialStep = draft.step || 0;
                    if (draft.selectedCategoryId) {
                        initialCat = categories.find(c => c.id === draft.selectedCategoryId) || null;
                    }
                    if (draft.formData) {
                        initialForm = {
                            ...initialForm,
                            ...draft.formData,
                            imageFile: null, imageBackFile: null, imageSideFile: null,
                            imageDetailsFiles: [], imagePreview: null,
                            imageBackPreview: null, imageSidePreview: null,
                            imageDetailsPreviews: []
                        };
                    }
                } catch (e) {
                    console.error("Error parsing draft:", e);
                }
            }
        }

        Promise.resolve().then(() => {
            setStep(initialStep);
            setSelectedCategory(initialCat);
            setFormData(initialForm);
        });
    }, [categories, initialCategoryId, initialSubcategoryId, setFormData, setSelectedCategory, setStep]);

    // Save draft on changes
    useEffect(() => {
        if (!isMounted) return;
        Promise.resolve().then(() => {
            setIsSaving(true);
        });
        const timer = setTimeout(() => {
            const dataToSave = {
                formData: {
                    ...formData,
                    imageFile: null,
                    imageBackFile: null,
                    imageSideFile: null,
                    imageDetailsFiles: [],
                    imagePreview: null,
                    imageBackPreview: null,
                    imageSidePreview: null,
                    imageDetailsPreviews: []
                },
                step,
                selectedCategoryId: selectedCategory?.id
            };
            if (typeof window !== "undefined") {
                localStorage.setItem("merch_crm_new_item_draft", JSON.stringify(dataToSave));
            }
            setIsSaving(false);
        }, 1000);

        return () => clearTimeout(timer);
    }, [formData, step, selectedCategory, isMounted, setIsSaving]);

    const clearDraft = () => {
        if (typeof window !== "undefined") {
            localStorage.removeItem("merch_crm_new_item_draft");
        }
    };

    const handleReset = () => {
        clearDraft();
        resetForm();
        toast("Форма сброшена", "info");
    };

    const subCategories = selectedCategory
        ? sortCategories(categories.filter(c => c.parentId === selectedCategory.id))
        : [];

    const isPackaging = selectedCategory?.name.toLowerCase().includes(CATEGORY_TYPES.packaging);

    const topLevelCategories = sortCategories(
        categories.filter(c => !c.parentId || c.parentId === "")
    );

    const hasSubCategories = subCategories.length > 0;

    const handleCategorySelect = (category: Category) => {
        setSelectedCategory(category);
        setValidationError("");

        setFormData((prev: ItemFormData) => ({
            ...prev,
            subcategoryId: "",
            brandCode: "",
            qualityCode: "",
            materialCode: "",
            attributeCode: "",
            sizeCode: "",
            itemName: "",
            attributes: {}
        }));
    };

    const handleSubCategorySelect = (subCategory: Category) => {
        if (subCategory.id === formData.subcategoryId) return;
        setValidationError("");
        updateFormData({
            subcategoryId: subCategory.id,
            attributes: {},
            brandCode: "",
            qualityCode: "",
            materialCode: "",
            attributeCode: "",
            sizeCode: ""
        });
    };

    const handleBack = () => {
        setValidationError("");
        window.scrollTo({ top: 0, behavior: 'smooth' });
        if (step === 2) {
            setStep(0);
        } else if (step === 1) {
            setStep(0);
        } else if (step > 2) {
            setStep(step - 1);
        } else {
            router.push(ROUTES.WAREHOUSE.CATEGORIES);
        }
    };

    const validateStep = (currentStep: number): boolean => {
        setValidationError("");
        if (currentStep === 0) {
            if (!selectedCategory) {
                setValidationError("Выберите категорию");
                return false;
            }
            const currentSubCategories = categories.filter(c => c.parentId === selectedCategory.id);
            if (currentSubCategories.length > 0 && !formData.subcategoryId) {
                setValidationError("Выберите подкатегорию");
                return false;
            }
        }

        const cleanCatName = selectedCategory?.name.toLowerCase().trim() || "";
        const isClothing = cleanCatName === CATEGORY_TYPES.clothing ||
            cleanCatName.startsWith(CATEGORY_TYPES.clothing + " ") ||
            cleanCatName.startsWith(CATEGORY_TYPES.clothing + ":");
        const isPackaging = cleanCatName.includes(CATEGORY_TYPES.packaging);

        if (currentStep === 2) {
            if (hasSubCategories && !formData.subcategoryId) {
                setValidationError("Выберите подкатегорию");
                return false;
            }

            if (isClothing) {

                // Helper to validate a standard field with a fallback to the attributes pool

                // All standard attributes are now optional as requested by the user
                // We no longer return false if isFieldValid is false
                /* 
                if (!isFieldValid("brand", "бренд", formData.brandCode)) {
                    setValidationError("Выберите бренд");
                    return false;
                }
                ...
                */
            } else if (isPackaging) {
                // Dimensions and weight are now optional as per user request to remove mandatory filling for all characteristic blocks

            } else {
                if (!formData.itemName) {
                    setValidationError("Введите название позиции");
                    return false;
                }
            }
        }



        if (currentStep === 4) {
            if (!formData.storageLocationId) {
                setValidationError("Выберите склад для хранения");
                return false;
            }
        }

        return true;
    };

    const handleNext = () => {
        if (!validateStep(step)) return;

        // Jump from 0 to 2 as 1 is currently obsolete/missing in Client and Sidebar
        if (step === 0) {
            setStep(2);
        } else {
            setStep(step + 1);
        }

        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleSubmit = async () => {
        if (!validateStep(step)) return;
        setIsSubmitting(true);
        setValidationError("");

        try {
            const submitFormData = new FormData();

            let itemType = "clothing";
            if (selectedCategory?.name.toLowerCase().includes(CATEGORY_TYPES.packaging)) itemType = "packaging";
            else if (selectedCategory?.name.toLowerCase().includes(CATEGORY_TYPES.consumables)) itemType = "consumables";

            submitFormData.append("itemType", itemType);

            submitFormData.append("name", formData.itemName || "");
            submitFormData.append("categoryId", formData.subcategoryId || selectedCategory?.id || "");
            submitFormData.append("sku", formData.sku || "");
            submitFormData.append("description", formData.description || "");
            submitFormData.append("quantity", String(formData.quantity) || "0");
            submitFormData.append("criticalStockThreshold", String(formData.criticalStockThreshold) || "0");
            submitFormData.append("lowStockThreshold", String(formData.lowStockThreshold) || "10");
            submitFormData.append("storageLocationId", formData.storageLocationId || "");
            submitFormData.append("costPrice", String(formData.costPrice) || "0");
            submitFormData.append("sellingPrice", String(formData.sellingPrice) || "0");

            submitFormData.append("qualityCode", formData.qualityCode || "");
            submitFormData.append("materialCode", formData.materialCode || "");
            submitFormData.append("brandCode", formData.brandCode || "");
            submitFormData.append("attributeCode", formData.attributeCode || "");
            submitFormData.append("sizeCode", formData.sizeCode || "");

            if (formData.width) submitFormData.append("width", String(formData.width));
            if (formData.height) submitFormData.append("height", String(formData.height));
            if (formData.depth) submitFormData.append("depth", String(formData.depth));
            if (formData.department) submitFormData.append("department", formData.department);

            if (formData.packagingType) submitFormData.append("packagingType", formData.packagingType);
            if (formData.supplierName) submitFormData.append("supplierName", formData.supplierName);
            if (formData.supplierLink) submitFormData.append("supplierLink", formData.supplierLink);
            if (formData.minBatch) submitFormData.append("minBatch", String(formData.minBatch));
            if (formData.weight) submitFormData.append("weight", String(formData.weight));
            if (formData.features) submitFormData.append("features", JSON.stringify(formData.features));

            if (formData.imageFile) submitFormData.append("image", formData.imageFile);
            if (formData.imageBackFile) submitFormData.append("imageBack", formData.imageBackFile);
            if (formData.imageSideFile) submitFormData.append("imageSide", formData.imageSideFile);
            formData.imageDetailsFiles?.forEach((img: File | null) => {
                if (img) submitFormData.append("imageDetails", img);
            });

            const attributes: Record<string, unknown> = {
                ...formData.attributes,
                thumbnailSettings: formData.thumbSettings
            };
            submitFormData.append("thumbnailSettings", JSON.stringify(formData.thumbSettings));
            submitFormData.append("attributes", JSON.stringify(attributes));

            const result = await addInventoryItem(submitFormData);

            if (!result?.success) {
                setValidationError(result.error);
                playSound("notification_error");
                setIsSubmitting(false);
            } else {
                clearDraft();
                playSound("item_created");
                toast("Позиция создана", "success");
                router.push(result.data?.id ? ROUTES.WAREHOUSE.ITEM_DETAIL(result.data.id) : ROUTES.WAREHOUSE.ROOT);
                router.refresh();
            }
        } catch (error) {
            console.error("[NEW_ITEM_SUBMIT] Error creating item:", error);
            setValidationError(
                error instanceof Error
                    ? error.message
                    : "Произошла ошибка при создании позиции"
            );
            playSound("notification_error");
            setIsSubmitting(false);
        }
    };

    const handleSidebarClick = (targetStep: number) => {
        if (targetStep === step) return;

        if (targetStep < step) {
            setStep(targetStep);
            setValidationError("");
            window.scrollTo({ top: 0, behavior: 'smooth' });
        } else {
            // Validate intermediate steps when jumping forward
            const allSteps = [0, 2, 3, 4, 5];
            const currentIndex = allSteps.indexOf(step);
            const targetIndex = allSteps.indexOf(targetStep);

            if (targetIndex === -1) return;

            // Validate from current step up to target - 1
            for (let i = currentIndex; i < targetIndex; i++) {
                const sId = allSteps[i];
                if (!validateStep(sId)) {
                    // validateStep will set the error message
                    return;
                }
            }

            setStep(targetStep);
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    return {
        step,
        selectedCategory,
        formData,
        validationError,
        isSaving,
        isSubmitting,
        subCategories,
        isPackaging,
        topLevelCategories,
        hasSubCategories,
        updateFormData,
        handleCategorySelect,
        handleSubCategorySelect,
        handleBack,
        handleNext,
        handleSubmit,
        handleReset,
        handleSidebarClick,
        setValidationError
    };
}

import { getInventoryCategories } from "../../category-actions";
import { getStorageLocations } from "../../storage-actions";
import { getMeasurementUnits } from "../../warehouse-shared.actions";
import { getInventoryAttributes, getInventoryAttributeTypes } from "../../attribute-actions";;
import { NewItemPageClient } from "./new-item-page-client";
import { AttributeType } from "../../types";

export const metadata = {
    title: "Склад | Новый товар",
    description: "Создание нового товара в складской системе",
};

export const dynamic = "force-dynamic";

export default async function NewItemPage({
    searchParams
}: {
    searchParams: Promise<{ categoryId?: string; subcategoryId?: string }>
}) {
    const { categoryId, subcategoryId } = await searchParams;

    // Загружаем все необходимые данные параллельно
    const [categoriesRes, locationsRes, unitsRes, attributesRes, typesRes, usersRes] = await Promise.all([
        getInventoryCategories(),
        getStorageLocations(),
        getMeasurementUnits(),
        getInventoryAttributes(),
        getInventoryAttributeTypes(),
        import("../../actions").then(m => m.getAllUsers())
    ]);

    const categories = (categoriesRes.success && 'data' in categoriesRes && categoriesRes.data) ? categoriesRes.data : [];
    const storageLocations = (locationsRes.success && 'data' in locationsRes && locationsRes.data) ? locationsRes.data : [];
    const measurementUnits = (unitsRes.success && 'data' in unitsRes && unitsRes.data) ? unitsRes.data : [];
    const dynamicAttributes = (attributesRes.success && 'data' in attributesRes && attributesRes.data) ? attributesRes.data : [];
    const attributeTypes = (typesRes.success && 'data' in typesRes && typesRes.data) ? typesRes.data : [];
    const users = (usersRes.success && 'data' in usersRes && usersRes.data) ? usersRes.data : [];

    return (
        <NewItemPageClient
            categories={categories}
            storageLocations={storageLocations}
            dynamicAttributes={dynamicAttributes}
            attributeTypes={attributeTypes as AttributeType[]}
            users={users}
            initialCategoryId={categoryId}
            initialSubcategoryId={subcategoryId}
        />
    );
}
